class Solution:
    def smallestEquivalentString(self, s1: str, s2: str, baseStr: str) -> str:
        parent = {c: c for c in 'abcdefghijklmnopqrstuvwxyz'}

        def find(c):
            if parent[c] != c:
                parent[c] = find(parent[c])
            return parent[c]

        def union(c1, c2):
            root1 = find(c1)
            root2 = find(c2)
            if root1 != root2:
                if root1 < root2:
                    parent[root2] = root1
                else:
                    parent[root1] = root2

        for c1, c2 in zip(s1, s2):
            union(c1, c2)

        groups = {}
        for c in 'abcdefghijklmnopqrstuvwxyz':
            root = find(c)
            if root not in groups:
                groups[root] = []
            groups[root].append(c)

        for group in groups.values():
            group.sort()

        result = []
        for c in baseStr:
            root = find(c)
            result.append(groups[root][0])

        return ''.join(result)
